import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import Webcam from "react-webcam";

const StudySession = ({ markDayComplete }) => {
    const { day } = useParams(); // Get the day number from the URL
    const navigate = useNavigate();
    const webcamRef = useRef(null);

    const [seconds, setSeconds] = useState(10); // Testing with 10 seconds
    const [isActive, setIsActive] = useState(false);
    const [showExplanation, setShowExplanation] = useState(false);
    const [explanation, setExplanation] = useState("");

    useEffect(() => {
        let interval = null;
        if (isActive && seconds > 0) {
            interval = setInterval(() => setSeconds(s => s - 1), 1000);
        } else if (seconds === 0) {
            clearInterval(interval);
            setShowExplanation(true);
        }
        return () => clearInterval(interval);
    }, [isActive, seconds]);

    const handleFinish = () => {
        // 1. Call the function passed from App.js to update state
        markDayComplete(day);
        
        // 2. Redirect back to dashboard
        navigate('/dashboard');
    };

    return (
        <div style={{ textAlign: 'center', padding: '40px' }}>
            {!showExplanation ? (
                <>
                    <h2>Day {day} Study Session</h2>
                    <div style={{ width: '400px', margin: '20px auto', borderRadius: '10px', overflow: 'hidden', border: '3px solid #2c3e50' }}>
                        <Webcam audio={false} ref={webcamRef} width="100%" />
                    </div>
                    <h1 style={{ fontSize: '4rem' }}>{Math.floor(seconds / 60)}:{String(seconds % 60).padStart(2, '0')}</h1>
                    <button onClick={() => setIsActive(!isActive)} style={{ padding: '10px 20px', cursor: 'pointer' }}>
                        {isActive ? 'Pause' : 'Start Focus'}
                    </button>
                </>
            ) : (
                <div style={{ maxWidth: '500px', margin: '0 auto' }}>
                    <h2>Time's Up!</h2>
                    <textarea 
                        placeholder="Explain what you learned..." 
                        style={{ width: '100%', height: '100px', padding: '10px' }}
                        value={explanation}
                        onChange={(e) => setExplanation(e.target.value)}
                    />
                    <br />
                    <button onClick={handleFinish} style={{ marginTop: '20px', background: 'green', color: 'white', padding: '10px 20px', cursor: 'pointer', border: 'none' }}>
                        Finish & Update Dashboard
                    </button>
                </div>
            )}
        </div>
    );
};

export default StudySession;
